import { streamText } from 'ai';
import { openai } from '@ai-sdk/openai';

export async function generateContent(prompt: string) {
  const result = await streamText({
    model: openai('gpt-4o'),
    prompt: `Write blog post about ${prompt}. Use professional tone. 800 words.`,
    maxTokens: 2000,
  });
  return result.toAIStreamResponse();
}

const BRAND_GUIDELINES = {
  tone: 'professional, approachable, optimistic',
  voice: 'first-person plural, conversational',
  restrictions: ['no jargon', 'avoid negativity'],
};

export async function generateBrandedContent(topic: string, guidelines: any) {
  const result = await streamText({
    model: openai('gpt-4o'),
    system: `Write using these brand guidelines: ${JSON.stringify(guidelines)}.`,
    prompt: `Create content about: ${topic}`,
  });
  return result;
}

import { tool } from 'ai';

const factCheckTool = tool({
  description: 'Verify factual claims',
  parameters: z.object({ claim: z.string() }),
  execute: async ({ claim }) => {
    // Integrate with Perplexity/Fact-check API
    return { verified: true, sources: ['source1.com'] };
  },
});

export async function generateVerifiedContent(prompt: string) {
  const result = await streamText({
    model: openai('gpt-4o'),
    tools: { factCheck: factCheckTool },
    prompt,
  });
  return result;
}

export async function generateSEOContent(topic: string, keywords: string[]) {
  const result = await streamText({
    model: openai('gpt-4o'),
    prompt: `Write SEO-optimized article about ${topic}. Required keywords: ${keywords.join(', ')}. Structure: H1, H2s, bullet lists, conclusion.`,
    temperature: 0.7,
    maxTokens: 1500,
  });

  return result.toAIStreamResponse();
}

