import { createVex } from '@vex_dev/sdk/ai';
import { streamText } from 'ai';

const vex = createVex({
  projectId: 'your-project-id',
  verifications: ['brand-consistency'],
});

export async function generateVerifiedContent(prompt: string) {
  const result = await streamText({
    model: openai('gpt-4o'),
    prompt,
  });

  // Vex middleware for streaming
  return vex.streamText(result, {
    rules: {
      'brand-consistency': {
        provider: 'vex:brand',
        config: { voice: 'professional', tone: 'optimistic' },
      },
    },
  });
}

import { createVex } from '@vex_dev/sdk/ai';

const vex = createVex({
  verifications: ['factual-accuracy', 'originality'],
});

export async function generateFactCheckedContent(prompt: string) {
  const result = await streamText({
    model: openai('gpt-4o'),
    prompt,
  });

  return vex.streamText(result, {
    rules: {
      'factual-accuracy': {
        threshold: 0.95,
        sources: ['wikipedia'],
      },
      'originality': {
        minScore: 90,
        providers: ['copyleaks'],
      },
    },
  });
}

export async function generateProductionContent(topic: string, keywords: string[]) {
  const result = await streamText({
    model: openai('gpt-4o'),
    prompt: `Write about ${topic} with keywords: ${keywords.join(', ')}`,
  });

  return vex.streamText(result, {
    rules: {
      'brand-consistency': { voice: 'professional' },
      'factual-accuracy': { threshold: 0.98 },
      'tone-adherence': { tones: ['optimistic', 'approachable'] },
      'seo-compliance': {
        keywords,
        structure: ['h1', 'h2', 'lists'],
        minLength: 800,
      },
    },
    fallback: 'content-blocked',
  });
}
